import { subscribeAction } from "./actions";

export const dynamic = "force-dynamic";

function getMessage(searchParams?: Record<string, string | string[] | undefined>) {
  const status = typeof searchParams?.status === "string" ? searchParams.status : "";
  const message = typeof searchParams?.message === "string" ? searchParams.message : "";

  return {
    status,
    message,
  };
}

export default async function UpdatesPage({
  searchParams,
}: {
  searchParams?: Promise<Record<string, string | string[] | undefined>>;
}) {
  const params = (await searchParams) ?? {};
  const { status, message } = getMessage(params);

  return (
    <main className="song-main">
      <div className="container updates-shell">
        <section className="updates-panel" data-reveal>
          <p className="eyebrow">Updates</p>
          <h1>Get new release updates</h1>
          <p className="lead">
            Join the email list to hear about new music, upcoming releases, and other updates from Wallerstedt.
          </p>
          <form className="updates-form" action={subscribeAction}>
            <label className="field">
              <span>Email</span>
              <input name="email" type="email" autoComplete="email" placeholder="you@example.com" required />
            </label>
            <button className="button button--primary" type="submit">
              Sign up
            </button>
          </form>
          {message ? (
            <p className={status === "error" ? "status-copy status-copy--error" : "status-copy"}>{message}</p>
          ) : null}
        </section>
      </div>
    </main>
  );
}
